final:
module RefModule(input [32-1:0] din, 
                                   input clk, en, rst,
                                   output reg [32-1:0] dout
    );  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt)
begin
  if(rst)
  dout <= 0;

  else
  if(en)
    dout <= din;

end 


endmodule
